def transpose(matrix):
    if not matrix:
        return matrix

    rows = len(matrix)
    cols = len(matrix[0])

    # If the matrix is square, transpose in place.
    if rows == cols:
        for i in range(rows):
            for j in range(i + 1, cols):
                matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]
        return matrix

    # For non-square matrices, return a transposed copy.
    return [[matrix[i][j] for i in range(rows)] for j in range(cols)]

